<body>
    <h1>Personal Expense Tracker</h1>

    <!-- Entry Form -->
    <div class="container">
        <h2>Add New Expense</h2>
        <form id="expense-form">
            <div class="form-group">
                <label for="amount">Amount ($)</label>
                <input type="number" id="amount" step="0.01" min="0.01" placeholder="Enter amount">
            </div>

            <div class="form-group">
                <label for="category">Category</label>
                <select id="category">
                    <option value="">Select category</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>

            <div class="form-group">
                <label for="date">Date</label>
                <input type="date" id="date">
            </div>

            <div class="form-group">
                <label for="note">Note (optional)</label>
                <input type="text" id="note" placeholder="Enter note">
            </div>

            <button type="submit" id="add-expense">Add Expense</button>
        </form>

        <div id="form-error" class="error-message"></div>
    </div>

    <!-- Filters -->
    <div class="container">
        <h2>Filters</h2>
        <div class="filter-section">
            <div class="filter-group">
                <label for="filter-category">Category</label>
                <select id="filter-category">
                    <option value="all">All Categories</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>

            <div class="filter-group">
                <label for="filter-from">From Date</label>
                <input type="date" id="filter-from">
            </div>

            <div class="filter-group">
                <label for="filter-to">To Date</label>
                <input type="date" id="filter-to">
            </div>
        </div>
    </div>

    <!-- Summary -->
    <div class="container summary-section">
        <h2>Summary</h2>
        <div class="total-display">Total: $<span id="total">0.00</span></div>
        <div class="cat-summary" id="category-totals">
            <!-- Category totals will be inserted here -->
        </div>
    </div>

    <!-- Expense List -->
    <div class="container">
        <h2>Expenses</h2>
        <ul id="expense-list" class="expense-list">
            <!-- Expenses will be inserted here -->
        </ul>
    </div>

    <script>
        // DOM Elements
        const expenseForm = document.getElementById('expense-form');
        const amountInput = document.getElementById('amount');
        const categorySelect = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');
        const addExpenseBtn = document.getElementById('add-expense');
        const formError = document.getElementById('form-error');

        const expenseList = document.getElementById('expense-list');
        const totalDisplay = document.getElementById('total');
        const categoryTotalsContainer = document.getElementById('category-totals');

        const filterCategory = document.getElementById('filter-category');
        const filterFrom = document.getElementById('filter-from');
        const filterTo = document.getElementById('filter-to');

        // Constants
        const CATEGORIES = ['groceries', 'transport', 'bills', 'fun'];
        const STORAGE_KEY = 'expenseTrackerData';

        // State
        let expenses = [];

        // Initialize
        function init() {
            loadExpenses();
            renderCategoryFilters();
            applyFiltersAndRender();

            // Set default date to today if empty
            if (!dateInput.value) {
                dateInput.valueAsDate = new Date();
            }

            // Event Listeners
            expenseForm.addEventListener('submit', handleFormSubmit);

            filterCategory.addEventListener('change', applyFiltersAndRender);
            filterFrom.addEventListener('change', applyFiltersAndRender);
            filterTo.addEventListener('change', applyFiltersAndRender);
        }

        // Load expenses from localStorage
        function loadExpenses() {
            const stored = localStorage.getItem(STORAGE_KEY);
            if (stored) {
                try {
                    expenses = JSON.parse(stored);
                } catch (e) {
                    console.error('Error parsing expenses:', e);
                    expenses = [];
                }
            }
        }

        // Save expenses to localStorage
        function saveExpenses() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
        }

        // Render category filter options
        function renderCategoryFilters() {
            // Clear existing options except 'all'
            while (filterCategory.options.length > 1) {
                filterCategory.remove(1);
            }

            // Add categories in order
            CATEGORIES.forEach(cat => {
                const option = document.createElement('option');
                option.value = cat;
                option.textContent = capitalizeFirstLetter(cat);
                filterCategory.add(option);
            });
        }

        // Capitalize first letter of a string
        function capitalizeFirstLetter(str) {
            return str.charAt(0).toUpperCase() + str.slice(1);
        }

        // Validate form inputs
        function validateForm() {
            const amount = parseFloat(amountInput.value);
            const category = categorySelect.value;
            const date = dateInput.value;

            let errorMessage = '';

            if (!date) {
                errorMessage = 'Please select a date.';
            } else if (!category) {
                errorMessage = 'Please select a category.';
            } else if (isNaN(amount) || amount <= 0) {
                errorMessage = 'Please enter a valid positive amount.';
            }

            return errorMessage;
        }

        // Handle form submission
        function handleFormSubmit(e) {
            e.preventDefault();

            const error = validateForm();

            if (error) {
                formError.textContent = error;
                formError.style.display = 'block';
                return;
            }

            // Clear error and reset amount field
            formError.style.display = 'none';
            amountInput.value = '';

            // Create new expense object
            const newExpense = {
                id: Date.now(),
                amount: parseFloat(amountInput.value),
                category: categorySelect.value,
                date: dateInput.value,
                note: noteInput.value.trim()
            };

            // Add to expenses array (newest first)
            expenses.unshift(newExpense);

            // Save and render
            saveExpenses();
            applyFiltersAndRender();

            // Reset form fields except date (keep today's date for convenience)
            categorySelect.value = '';
            noteInput.value = '';
        }

        // Delete expense
        function deleteExpense(id) {
            expenses = expenses.filter(expense => expense.id !== id);
            saveExpenses();
            applyFiltersAndRender();
        }

        // Apply filters and render expenses
        function applyFiltersAndRender() {
            const categoryFilter = filterCategory.value;
            const fromFilter = filterFrom.value;
            const toFilter = filterTo.value;

            let filteredExpenses = [...expenses];

            // Apply category filter
            if (categoryFilter !== 'all') {
                filteredExpenses = filteredExpenses.filter(expense => expense.category === categoryFilter);
            }

            // Apply date filters
            if (fromFilter) {
                const from = new Date(fromFilter);
                from.setHours(0, 0, 0, 0);

                filteredExpenses = filteredExpenses.filter(expense => {
                    const expenseDate = new Date(expense.date);
                    expenseDate.setHours(0, 0, 0, 0);
                    return expenseDate >= from;
                });
            }

            if (toFilter) {
                const to = new Date(toFilter);
                to.setHours(23, 59, 59, 999);

                filteredExpenses = filteredExpenses.filter(expense => {
                    const expenseDate = new Date(expense.date);
                    expenseDate.setHours(0, 0, 0, 0);
                    return expenseDate <= to;
                });
            }

            // Render expenses
            renderExpenses(filteredExpenses);

            // Update totals
            updateTotals(filteredExpenses);
        }

        // Render expense list
        function renderExpenses(expensesToRender) {
            expenseList.innerHTML = '';

            if (expensesToRender.length === 0) {
                expenseList.innerHTML = '<li style="text-align: center; color: #666;">No expenses found.</li>';
                return;
            }

            expensesToRender.forEach(expense => {
                const li = document.createElement('li');
                li.className = 'expense';

                // Format amount
                const formattedAmount = expense.amount.toFixed(2);

                // Format date
                const dateObj = new Date(expense.date);
                const formattedDate = dateObj.toLocaleDateString();

                li.innerHTML = `
                    <div class="expense-info">
                        <span class="expense-amount">$${formattedAmount}</span>
                        <span class="expense-details">${capitalizeFirstLetter(expense.category)} • ${formattedDate}</span>
                        ${expense.note ? `<br><span style="color: #888; font-size: 13px;">${escapeHtml(expense.note)}</span>` : ''}
                    </div>
                    <button class="exp-del" data-id="${expense.id}">Delete</button>
                `;

                expenseList.appendChild(li);
            });

            // Add delete event listeners
            document.querySelectorAll('.exp-del').forEach(btn => {
                btn.addEventListener('click', function() {
                    const id = parseInt(this.getAttribute('data-id'));
                    deleteExpense(id);
                });
            });
        }

        // Update totals display
        function updateTotals(expensesToSum) {
            // Calculate total
            const total = expensesToSum.reduce((sum, expense) => sum + expense.amount, 0);
            totalDisplay.textContent = total.toFixed(2);

            // Calculate per-category totals for visible expenses
            const categoryTotals = {};

            CATEGORIES.forEach(cat => {
                categoryTotals[cat] = 0;
            });

            expensesToSum.forEach(expense => {
                if (categoryTotals.hasOwnProperty(expense.category)) {
                    categoryTotals[expense.category] += expense.amount;
                }
            });

            // Render category totals
            categoryTotalsContainer.innerHTML = '';

            CATEGORIES.forEach(cat => {
                const amount = categoryTotals[cat];
                if (amount > 0 || expenses.some(e => e.category === cat)) {
                    const div = document.createElement('div');
                    div.className = 'cat-total';
                    div.setAttribute('data-cat', cat);
                    div.textContent = `${capitalizeFirstLetter(cat)}: $${amount.toFixed(2)}`;

                    categoryTotalsContainer.appendChild(div);
                }
            });
        }

        // Escape HTML to prevent XSS
        function escapeHtml(text) {
            const div = document.createElement('div');
            div.textContent = text;
            return div.innerHTML;
        }

        // Initialize the app
        init();
    </script>
</body>
</html>
